// Parse GPT response
const response = $input.first().json;
const content = JSON.parse(response.choices[0].message.content);

return {
  json: {
    strategy: content.strategy,
    script: content.script,
    midjourney_prompts: content.midjourney_prompts,
    timing: content.timing,
    performance_estimate: content.performance_estimate,
    product_name: $('Extract Product Data').first().json.product_name,
    total_images: content.midjourney_prompts.length
  }
};

// Collect all images with their timing metadata
const allInputs = $input.all();
const strategy = $('Parse Strategy').first().json;

const images = allInputs.map((item, index) => ({
  binary: item.binary,
  json: {
    index: index,
    timing: strategy.timing[index]
  }
}));

return images;

// Build ADVANCED Shotstack timeline
const strategy = $('Parse Strategy').first().json;
const images = $input.all().filter(item => item.binary?.data);
const voiceover = $('ElevenLabs Voiceover').first();
const musicUrl = $('Extract Product Data').first().json.music_url;
const musicVolume = $('Extract Product Data').first().json.music_volume;

// Advanced transition mapping
const transitionMap = {
  'fade': { in: 'fade', out: 'fade' },
  'wipeLeft': { in: 'wipeLeft', out: 'fade' },
  'wipeRight': { in: 'wipeRight', out: 'fade' },
  'zoomIn': { in: 'zoomIn', out: 'fade' },
  'slideUp': { in: 'slideUp', out: 'fade' },
  'slideDown': { in: 'slideDown', out: 'fade' },
  'slideLeft': { in: 'slideLeft', out: 'fade' },
  'slideRight': { in: 'slideRight', out: 'fade' }
};

// Effect mapping for Ken Burns + motion
const effectMap = {
  'zoomIn': 'zoomIn',
  'zoomOut': 'zoomOut',
  'zoomInSlow': 'zoomInSlow',
  'slideLeft': 'slideLeft',
  'slideRight': 'slideRight',
  'slideUp': 'slideUp',
  'slideDown': 'slideDown'
};

// Build image clips with ADVANCED effects
let currentTime = 0;
const imageClips = strategy.timing.map((timing, index) => {
  const transition = transitionMap[timing.transition] || transitionMap['fade'];
  const effect = effectMap[timing.effect] || 'zoomIn';

  const clip = {
    asset: {
      type: 'image',
      src: `data:image/png;base64,${images[index].binary.data.toString('base64')}`
    },
    start: currentTime,
    length: timing.duration,
    fit: 'cover',
    scale: 1.15, // Enhanced Ken Burns effect
    transition: transition,
    effect: effect,
    opacity: 1
  };

  currentTime += timing.duration;
  return clip;
});

const totalDuration = currentTime;

// Build timeline
const timeline = {
  tracks: [
    // Track 1: Images with effects
    { clips: imageClips },
    // Track 2: Voiceover
    {
      clips: [
        {
          asset: {
            type: 'audio',
            src: `data:audio/mpeg;base64,${voiceover.binary.data.toString('base64')}`
          },
          start: 0,
          length: totalDuration,
          volume: 1.0
        }
      ]
    }
  ]
};

// Add background music if provided
if (musicUrl) {
  timeline.soundtrack = {
    src: musicUrl,
    effect: 'fadeInFadeOut',
    volume: musicVolume
  };
}

// Track 3: Animated text overlays
const textClips = strategy.timing
  .filter(t => t.text_overlay)
  .map(timing => {
    const startTime = strategy.timing.slice(0, timing.image).reduce((sum, t) => sum + t.duration, 0);

    return {
      asset: {
        type: 'title',
        text: timing.text_overlay,
        style: 'minimal',
        color: '#ffffff',
        size: 'large',
        background: 'rgba(0,0,0,0.65)',
        position: timing.image === 0 ? 'top' : (timing.image === strategy.timing.length - 1 ? 'bottom' : 'center')
      },
      start: startTime + 0.3,
      length: Math.min(2.5, timing.duration - 0.5),
      transition: {
        in: 'slideUp',
        out: 'fade'
      },
      effect: 'zoomIn'
    };
  });

if (textClips.length > 0) {
  timeline.tracks.push({ clips: textClips });
}

return {
  json: {
    timeline: timeline,
    output: {
      format: 'mp4',
      resolution: '1080',
      aspectRatio: '9:16',
      fps: 30,
      quality: 'high'
    }
  }
};
